var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"하아...... 컨디션 조절도 못하고 병가를 써 버리다니......","JPN":"はあ……体調管理ができず病欠になるなんて……","ENG":"*Sigh* I can't believe I had to take sick leave because I overworked myself...","TWN":"哈啊……沒能管理好身體，就突然休了病假……"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그러고 보니 레나 양은 잘하고 있으려나?","JPN":"今頃レナさんはうまくやってくれているかな？","ENG":"I wonder how Lena's doing?","TWN":"也不知道蕾娜能不能應付得來？"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"모르는 일이 있으면 전화 달라고 했는데 문자 한 통 안 왔고......","JPN":"わからないことがあれば電話してと言ったのに、メッセージも何もないし……","ENG":"I told her to call me if she gets stuck, but she hasn't texted at all.","TWN":"跟她說有什麼不懂的就給我打電話的，怎麼連個簡訊都沒有……"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"혹시......?","JPN":"もしかして……？","ENG":"Wait... Could she be...","TWN":"難道……？"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이미 회사가 입은 손해는 레나 양이 책임질 수 있는 범위를 넘어섰어요.","JPN":"すでに会社に与えた損害は、レナさんが責任を負える限度を超えています。","ENG":"The amount of damage suffered by the company is already well beyond what you can compensate, Lena.","TWN":"公司受到的損失，已經不是蕾娜妳可以負責的程度了。"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"긴 말 안 하겠습니다. 내일부터는 출근하지 않으셔도 돼요.","JPN":"単刀直入に言います。明日から出社しなくて大丈夫です。","ENG":"I'll be blunt. I'm going to have to let you go now.","TWN":"廢話就不多說了，明天開始妳不用上班了。"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"잘못했어요, 부사장님! 한 번만 더 기회를 주세요!","JPN":"も、申し訳ございません、副社長！　もう一度チャンスをください！","ENG":"I'm so sorry, ma'am! Please give me one more chance!","TWN":"副總，對不起！再給我一次機會吧！"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"설마...... 그런 일이 벌어지진 않았겠지?","JPN":"まさか……そんなことが起きたりはしてないよね……？","ENG":"She's not going to get fired like that... is she?","TWN":"不會……不會發生這種事吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"기다리세요, 레나 양! 지금 갈게요!","JPN":"待っててください、レナさん！　ナカシマが今行きます！","ENG":"Hold on, Lena! I'll be right there!","TWN":"等我，蕾娜！我現在就去！"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>업계인들이 만드는 뉴스, 태스크포스 리빌. 다음 소식입니다.</color>","JPN":"<color=#ffd34c>業界人が作るニュース、タスクフォース・リビール。次のニュースです。</color>","ENG":"<color=#ffd34c>This is TASKFORCE Reveal, your trusted news source on all things in the industry. Here's the news.</color>","TWN":"<color=#ffd34c>業界人的新聞，特遣勢力為您報導下一個消息。</color>"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>최근 그라운드 원 시가지에서 측정되는 침식파가 불안정한 양상을 띄고 있다고 밝혔습니다.</color>","JPN":"<color=#ffd34c>最近グラウンド・ワン市街地で計測される侵食波が、不安定な状況であることが明らかになりました。</color>","ENG":"<color=#ffd34c>Recently, the Corruption Rays detected from Ground One have shown signs of instability.</color>","TWN":"<color=#ffd34c>最近發現在G1市區測到的侵蝕波情況不穩定。</color>"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>도시관리국은 관할 태스크포스들이 제출한 13개 구역의 통행 자제를 권고하였으며......</color>","JPN":"<color=#ffd34c>都市管理局は管轄タスクフォースカンパニーが提出した13のエリアに通行を控えることを勧告し……</color>","ENG":"<color=#ffd34c>The City Management has urged restricted movement in the 13 sectors recommended by the respective TASKFORCEs...</color>","TWN":"<color=#ffd34c>城市管理局建議管轄特遣勢力提交的13個區域禁止通行……</color>"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"왠지...... 평소보다 더 차분하네?","JPN":"なんだか……いつもより落ち着いている……？","ENG":"Strange... It's actually a lot more serene than usual.","TWN":"感覺……比平時冷靜呢。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"잘 왔네, 관리부장. 푹 쉬었나?","JPN":"おおーおはよう、管理部長。ゆっくり休めたか？","ENG":"Welcome back, Manager. Are you feeling better?","TWN":"妳來得正好，管理部長。休息足夠了嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아, 네! 덕분에!","JPN":"あ、はい！　おかげさまで。","ENG":"Oh, yes! Thank you.","TWN":"啊，是！謝謝！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그런데...... 옆에 계신 분은 누구시죠?","JPN":"ところで……隣にいる方はどなたでしょう？","ENG":"By the way... Who is that next to you?","TWN":"那個……旁邊這位是？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"베로니카라고 합니다, 관리부장님. 주인님께 말씀 많이 들었습니다.","JPN":"ベロニカと申します、管理部長。ご主人様からお話は聞いております。","ENG":"It's a pleasure to meet you, Manager Kim. I'm Veronica. The Master has told me much about you.","TWN":"我叫貝洛妮卡，我聽主人提到過管理部長。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아...... 네.","JPN":"あ……はい。","ENG":"Oh... Okay.","TWN":"啊……這樣啊。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"사장님, 회사에서 이런 특별한 취향의 애정 행각을 펼치시면 안 되죠.","JPN":"社長、会社に性癖による趣味を持ち込むのはまずいと思いませんか？","ENG":"Boss, you really shouldn't bring your... private activities to the workplace.","TWN":"老闆，你怎麼可以在公司這麼明目張膽的秀恩愛？而且還是這種特殊的癖好。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"따님도 계시잖아요.","JPN":"娘さんもいらっしゃるのに。","ENG":"Your daughter works here.","TWN":"你還有女兒呢。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"자네 오자마자 무슨 큰일날 소리인가!? 오해야, 오해!","JPN":"き、君はいったい何を言っている！？　誤解だぞ、誤解！","ENG":"No, no, no! What are you talking about? You got it all wrong!","TWN":"什麼亂七八糟的？！這是誤會，誤會啊！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그러니까...... 요약하자면 난장판이 된 회사를 치우려고 청소 업체를 불렀더니 진짜 메이드가 왔다는 건가요?","JPN":"えーと……つまり、散らかってしまった会社を片付けようとして清掃業者を呼んだら、本物のメイドが来たということですか？","ENG":"So... In short, you called for a cleaning service to take care of the messy office, only to realize that they're real maids?","TWN":"所以是……為了清掃亂七八糟的公司，你叫了清潔公司，然後就真的來了位女僕？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"역시 관리부장이야! 이해가 빠르군!","JPN":"さすが管理部長！　理解がはやいな！","ENG":"I knew you'd get it!","TWN":"果然是管理部長！理解能力優秀！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"하나도 이해 못했어요.","JPN":"いいえ、まったく理解できていません。","ENG":"Actually, I don't get it at all.","TWN":"我一點都沒有理解。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"흠. 하지만 어쩌겠나. 그게 바로 명백한 사실인 것을.","JPN":"ふむ。でも仕方ないじゃないか。それが噓偽りのない事実なんだからな。","ENG":"Hmm... But what are you going to do? It is what it is.","TWN":"唉，我說的就是事實。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L50_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"이게 다 내가 인재복이 많은 덕분이지. 하. 하. 하.","JPN":"これも全て、ついつい良い人材を引き寄せてしまう私の魅力のせいだろう。アハハハ！","ENG":"I can't help it that I'm a natural magnet for talent. Hah, hah, hah...","TWN":"只能說我這個人和人才有緣啊，哈.哈.哈。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"후훗. 과찬이세요, 주인님.","JPN":"フフッ、良い人材だなんて身に余るお言葉です、ご主人様。","ENG":"Hah hah, that is most flattering, Master.","TWN":"呼呼，過獎了，主人。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그리고 관리부장님, 복귀하시자마자 죄송하지만 검토를 부탁드릴 안건이 있습니다.","JPN":"そして管理部長様、復帰早々申し訳ございませんが、ぜひ確認いただきたい案件がございます。","ENG":"And Manager, I'd hate to burden you right after your sick leave, but there's something I was hoping you could review.","TWN":"管理部長，很抱歉，這裡有個案件需要您審批一下。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"네? 검토라니요?","JPN":"案件とは？","ENG":"Huh? Review what?","TWN":"什麼？審批？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"최근 6개월간 누락됐던 보급품 손망실을 조사한 보고서입니다.","JPN":"ここ6ヶ月間、抜けていた補給品の損失を調査した報告書です。","ENG":"It's a loss and damage report that details all the information omitted over the past six months.","TWN":"這是最近6個月遺漏的補給品損失調查報告。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그리고 여기, 입찰 가능한 정화 작전 의뢰들의 위험 대비 수익률을 조사해 뒀습니다.","JPN":"そしてこちらに、入札可能な浄化作戦依頼のリスクや危険度に対する収益率を調べておきました。","ENG":"And here is a list of all the operations open for bidding, and their respective profitability estimates.","TWN":"還有，這些是可投標的淨化作戰委託，我調查了一下基於風險的收益率。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"마지막으로 부재 중이셨을 때 별도로 정리해 둔 회계장부입니다.","JPN":"最後に、ご不在中に別途整理しておいた会計帳簿です。","ENG":"Lastly, I've taken the liberty of organizing the accounting book while you were absent.","TWN":"最後，這是您不在期間我整理的會計帳簿。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"표정이 어두워지셨군요. 제가 무언가 결례를 범했을까요?","JPN":"顔色が暗いですね。何か非礼なことを申し上げてしまいましたでしょうか？","ENG":"You seem upset. Have I offended you somehow?","TWN":"您的臉色看起來有些不好，我是不是失禮了？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아뇨. 생각해 보면 저도 직장 생활을 참 험난하게 한 것 같아서요.","JPN":"いいえ。よく考えてみたら、今までこんな厳しい環境の職場でよく働いていたなと、改めて思っただけです。","ENG":"No... I just realized how rough I had it while working here.","TWN":"沒有，想想我的職場生活也是夠艱難的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"사장님부터 직원들까지 전부 자기 주장이 너무 강해서 고생이었거든요.","JPN":"社長をはじめ社員みんな、自己主張が激しすぎる人ばかりでこれまで散々苦労していました。","ENG":"Everyone here is so stubborn, from the CEO to every employee. They never made life easy for me.","TWN":"從老闆到員工，每個人都很有個性，我夾在中間也是很疲憊。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"뜨끔.","JPN":"(ドキッ)","ENG":"Uh-oh.","TWN":"(心虛)"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그런데 이렇게 성실하고 꼼꼼한 분이 우리 회사에 와 주시다니!","JPN":"ですが、ついに！　こんなに真面目で几帳面な方がうちの会社に来てくれるなんて！","ENG":"But now we have someone so diligent and meticulous with us!","TWN":"不過，還好有妳這麼踏實又細心的人來到了我們公司。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"마침 관리부 직원을 채용해야겠다고 생각하던 참이었는데 잘됐네요.","JPN":"ちょうど管理部にスタッフを採用しようとしていたところだったので、嬉しいです。","ENG":"I've been wanting to hire some extra staff for my department. And you're the perfect fit.","TWN":"剛好我要招聘管理部職員。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"사무실에 자리를 만들어 드릴게요. 오늘 바로 준비할까요, 사장님?","JPN":"事務室に席を用意します。本日からでもいいですか、社長？","ENG":"I'll set up a desk for you in the office. Should we get it done today, Boss?","TWN":"就在辦公室給妳騰個位置吧。老闆，今天辦理入職如何？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그거 좋지. 본인도 괜찮다면야.","JPN":"もちろんさ。本人がよければな。","ENG":"Sounds good. As long as she's okay with it.","TWN":"很好，如果本人同意的話。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"베로니카 양, 이 참에 아예 우리가 처음에 맺은 단기 계약 대신 장기 계약을 하면 어떻겠나?","JPN":"ベロニカ、これも縁だし最初に結んだ短期契約ではなく、長期契約を結ぶのはどうかね？","ENG":"Veronica, why don't we extend that short-term contract to a long-term one?","TWN":"貝洛妮卡，要不我們直接簽一個長期合約吧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"요 며칠 봤다시피 회사가 자주 어수선해서 말이야.","JPN":"ここ数日で実際に見てもらってわかったと思うが、社内がごちゃごちゃになってしまうことが多くてな。","ENG":"As you may have noticed over the past few days, this company's in shambles more often than not.","TWN":"妳也看到了，這幾天公司經常亂糟糟的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"원래 있던 청소 요원이 잠시 고향으로 돌아간 지금, 자네처럼 믿음직한 파트너는 언제든 환영일세.","JPN":"元々いた清掃員のスタッフが帰省している今、君のような頼もしいスタッフはいつでも大歓迎だ。","ENG":"Since our cleaning agent is away on a trip for the time being, we'd welcome a reliable partner like you with open arms.","TWN":"原來的清潔工暫時回老家了，所以我很歡迎像妳這樣可靠的人成為我的合作夥伴。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"귀중한 기회를 선뜻 제안해 주셔서 감사합니다. 주인님.","JPN":"貴重な機会を提案してくださったのは嬉しいです、ご主人様。","ENG":"Thank you for this outstanding offer, Master.","TWN":"感謝您給我這個寶貴的機會，主人。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그렇지만 저희는 사정상 장기 계약을 맺기 어렵습니다.","JPN":"しかし我々は諸事情により、長期契約を結ぶのは難しいのです。","ENG":"Unfortunately, we are unable to enter into long-term contracts due to certain circumstances.","TWN":"但恐怕我們無法和您簽長期約。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"으응? 혹시 법적인 문제라도 있어서 그러나?","JPN":"それは法的な問題かね？","ENG":"Hmm? Is it a legal issue?","TWN":"嗯？怎麼？是因為有法律上的問題嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"아뇨. 주인님께 말씀드리기에는 변변찮은 이유입니다.","JPN":"いいえ。ご主人様に申し上げられるような大した理由ではありません。","ENG":"No. It's far too trivial to bother you with the details.","TWN":"不是，是個小問題，小到我都不好意思跟您說。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"저는 이만 다른 일을 처리하러 가 보겠습니다. 필요하실 때 언제든 불러 주시길.","JPN":"それでは、他の仕事が残っていますので失礼いたします。必要な時はいつでもお呼びください。","ENG":"I'd better go take care of some other business. Please feel free to call me when you need me.","TWN":"那我先去工作了，有需要再叫我吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"저 분...... 뭔가 숨기고 계신 것 같네요.","JPN":"あの方……何か隠しているようですね。","ENG":"She seems to be hiding something.","TWN":"她好像……在隱瞞些什麼。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"으음. 나쁜 꿍꿍이가 있어 보이진 않네만.","JPN":"ふむ。何か魂胆があるようには見えないんだが。","ENG":"Hmm... Well, it doesn't seem like she's got any nefarious plans.","TWN":"唔，不過她不像是心懷鬼胎的人。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"참, 그러고 보니 레나 양이 자네 오기만 벼르고 있었다네. 가서 안심 좀 시켜 주게나.","JPN":"そうだ、そういえばレナ君がずっと君の復帰を心待ちにしていたから、彼女の所に行って安心させてあげなさい。","ENG":"Oh, I just remembered Lena's been waiting for you. Why don't you go comfort her?","TWN":"對了，蕾娜一直在等妳回來，妳快去看看她吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아, 그렇겠네요. 많이 당황했을 텐데.","JPN":"あ、そうですね。急に色々任せられて相当慌てていたでしょう。","ENG":"Oh, right. She must have had a tough time.","TWN":"也是，她應該也很慌亂。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그럼 저도 작전부에 가 보겠습니다.","JPN":"それでは、私も作戦部に戻ります。","ENG":"I'll go to the Operation Department then.","TWN":"那我去作戰部了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"관리부 인력 충원 건은 꼭 고려해 주세요, 사장님.","JPN":"管理部の人員補充の件はぜひご検討をお願いします、社長。","ENG":"Please do give some thought to hiring more personnel for the Managerial Department though.","TWN":"關於管理部的人員補充問題，請好好考慮一下吧，老闆。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"흐음......","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};